CREATE DATABASE IF NOT EXISTS melodyrent CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE melodyrent;
CREATE TABLE IF NOT EXISTS roles (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(40) UNIQUE NOT NULL, created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS users (id BIGINT PRIMARY KEY AUTO_INCREMENT, full_name VARCHAR(160) NOT NULL, email VARCHAR(160) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, avatar_url VARCHAR(500), reward_points INT DEFAULT 0, level VARCHAR(40), created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS user_roles (user_id BIGINT NOT NULL, role_id BIGINT NOT NULL, PRIMARY KEY(user_id, role_id), FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(role_id) REFERENCES roles(id));
CREATE TABLE IF NOT EXISTS categories (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(120) UNIQUE NOT NULL, icon VARCHAR(80), gradient VARCHAR(160), created_at TIMESTAMP, updated_at TIMESTAMP);
CREATE TABLE IF NOT EXISTS products (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(220) NOT NULL, description TEXT, base_price_per_day DECIMAL(12,2) NOT NULL, city VARCHAR(120) NOT NULL, inventory INT NOT NULL, approved BOOLEAN DEFAULT FALSE, available BOOLEAN DEFAULT TRUE, model3d_url VARCHAR(500), category_id BIGINT NOT NULL, owner_id BIGINT NOT NULL, created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(category_id) REFERENCES categories(id), FOREIGN KEY(owner_id) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS product_images (id BIGINT PRIMARY KEY AUTO_INCREMENT, url VARCHAR(700) NOT NULL, public_id VARCHAR(220), product_id BIGINT NOT NULL, created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS music_tracks (id BIGINT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(200) NOT NULL, artist VARCHAR(160), url VARCHAR(700) NOT NULL, duration_seconds INT, product_id BIGINT NOT NULL, created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS bookings (id BIGINT PRIMARY KEY AUTO_INCREMENT, customer_id BIGINT NOT NULL, product_id BIGINT NOT NULL, start_date DATE NOT NULL, end_date DATE NOT NULL, total_price DECIMAL(12,2) NOT NULL, status VARCHAR(40), created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(customer_id) REFERENCES users(id), FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS payments (id BIGINT PRIMARY KEY AUTO_INCREMENT, booking_id BIGINT NOT NULL, amount DECIMAL(12,2) NOT NULL, provider VARCHAR(80), provider_reference VARCHAR(220), status VARCHAR(40), created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(booking_id) REFERENCES bookings(id));
CREATE TABLE IF NOT EXISTS reviews (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, product_id BIGINT NOT NULL, rating INT NOT NULL, comment TEXT, created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS wishlists (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, product_id BIGINT NOT NULL, created_at TIMESTAMP, updated_at TIMESTAMP, UNIQUE KEY uk_wishlist(user_id, product_id), FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS user_activity (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, product_id BIGINT, type VARCHAR(40), metadata VARCHAR(1000), created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id), FOREIGN KEY(product_id) REFERENCES products(id));
CREATE TABLE IF NOT EXISTS pricing_rules (id BIGINT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(160) NOT NULL, multiplier DECIMAL(5,2) NOT NULL, starts_on DATE, ends_on DATE, category_id BIGINT, active BOOLEAN DEFAULT TRUE, created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(category_id) REFERENCES categories(id));
CREATE TABLE IF NOT EXISTS notifications (id BIGINT PRIMARY KEY AUTO_INCREMENT, user_id BIGINT NOT NULL, title VARCHAR(160) NOT NULL, message VARCHAR(1000), read_flag BOOLEAN DEFAULT FALSE, deep_link VARCHAR(500), created_at TIMESTAMP, updated_at TIMESTAMP, FOREIGN KEY(user_id) REFERENCES users(id));
